import { cacheTag } from 'next/cache'

/**
 * In-memory product catalog simulating data sourced from an ERP/PIM system.
 * In production this would be a database — the caching layer ('use cache' +
 * cacheTag) keeps reads fast and avoids querying the DB on every request.
 */

let data = [
  { id: 'SKU-001', name: 'Laptop Pro 15"',     price: 1299, inventory: 42,  status: 'active',        lastUpdated: new Date(Date.now() - 3_600_000).toISOString() },
  { id: 'SKU-002', name: 'Wireless Headphones', price: 249,  inventory: 157, status: 'active',        lastUpdated: new Date(Date.now() - 7_200_000).toISOString() },
  { id: 'SKU-003', name: 'Smart Watch',         price: 399,  inventory: 88,  status: 'active',        lastUpdated: new Date(Date.now() - 1_800_000).toISOString() },
  { id: 'SKU-004', name: 'Tablet 11"',          price: 599,  inventory: 23,  status: 'active',        lastUpdated: new Date(Date.now() - 5_400_000).toISOString() },
  { id: 'SKU-005', name: 'USB-C Hub',           price: 79,   inventory: 0,   status: 'out_of_stock',  lastUpdated: new Date(Date.now() - 9_000_000).toISOString() },
  { id: 'SKU-006', name: 'Mechanical Keyboard', price: 149,  inventory: 312, status: 'active',        lastUpdated: new Date(Date.now() - 3_600_000).toISOString() },
  { id: 'SKU-007', name: '27" 4K Monitor',      price: 449,  inventory: 15,  status: 'active',        lastUpdated: new Date(Date.now() - 10_800_000).toISOString() },
  { id: 'SKU-008', name: 'Webcam 4K',           price: 199,  inventory: 0,   status: 'discontinued',  lastUpdated: new Date(Date.now() - 86_400_000).toISOString() },
  { id: 'SKU-009', name: 'Ergonomic Mouse',     price: 89,   inventory: 204, status: 'active',        lastUpdated: new Date(Date.now() - 1_800_000).toISOString() },
  { id: 'SKU-010', name: 'Laptop Stand',        price: 59,   inventory: 89,  status: 'active',        lastUpdated: new Date(Date.now() - 7_200_000).toISOString() },
]

// Track the most recent ERP sync timestamp (for display / staleness indicators).
let lastSyncTimestamp = data.reduce((latest, p) => {
  const t = new Date(p.lastUpdated).getTime()
  return t > latest ? t : latest
}, 0)

/**
 * Returns the full product catalog.
 *
 * The `'use cache'` directive caches the return value in the Next.js cache
 * layer. `cacheTag('products')` lets us invalidate this cache on demand via
 * `revalidateTag('products', 'max')` — after a sync the stale cache is served
 * while fresh data loads in the background (stale-while-revalidate).
 */
export async function getAllProducts() {
  'use cache'
  cacheTag('products')

  // Simulate a database round-trip — 100 ms of realistic latency.
  await new Promise((resolve) => setTimeout(resolve, 100))

  return data.map((p) => ({ ...p }))
}

/**
 * Simulates an upstream ERP/PIM sync that refreshes pricing, inventory, and
 * availability for the entire catalog.  In production this would call an
 * external API or read a feed, potentially taking seconds for thousands of
 * SKUs.
 *
 * After this completes, consumers should call:
 *   revalidateTag('products', 'max')
 * so that cached catalog data is refreshed in the background without blocking
 * the admin's next page view.
 */
export async function syncCatalogFromERP() {
  // Simulate the time a real upstream sync takes — long enough that you
  // wouldn't want every page request to wait on it.
  await new Promise((resolve) => setTimeout(resolve, 1_500))

  const now = Date.now()

  data = data.map((product) => {
    // Simulate realistic price/inventory fluctuations from the upstream system.
    const priceDelta = Math.floor(Math.random() * 30) - 10 // -10 .. +19
    const inventoryDelta = Math.floor(Math.random() * 25) - 3 // -3 .. +21

    return {
      ...product,
      price: Math.max(1, product.price + priceDelta),
      inventory: Math.max(0, product.inventory + inventoryDelta),
      status:
        product.inventory + inventoryDelta > 0
          ? 'active'
          : 'out_of_stock',
      lastUpdated: new Date(now).toISOString(),
    }
  })

  lastSyncTimestamp = now

  return { synced: true, timestamp: now, productCount: data.length }
}

/**
 * Returns the Unix-millisecond timestamp of the most recent ERP sync
 * (or the oldest product's timestamp if never synced).
 */
export function getLastSyncTimestamp() {
  return lastSyncTimestamp
}

