import { revalidateTag } from 'next/cache'
import {
  getAllProducts,
  syncCatalogFromERP,
  getLastSyncTimestamp,
} from '@/lib/db'

// ────────────────────────────────────────────────────────────────────────────
// Helpers
// ────────────────────────────────────────────────────────────────────────────

function formatTimestamp(ts) {
  return new Date(ts).toLocaleString('en-US', {
    month: 'short',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  })
}

function timeAgo(ts) {
  const seconds = Math.floor((Date.now() - ts) / 1000)
  if (seconds < 60) return 'just now'
  const minutes = Math.floor(seconds / 60)
  if (minutes < 60) return `${minutes}m ago`
  const hours = Math.floor(minutes / 60)
  if (hours < 24) return `${hours}h ago`
  return `${Math.floor(hours / 24)}d ago`
}

function statusBadge(status) {
  const styles = {
    active: { bg: '#dcfce7', color: '#166534' },
    out_of_stock: { bg: '#fef3c7', color: '#92400e' },
    discontinued: { bg: '#fce4ec', color: '#9a0007' },
  }
  const s = styles[status] ?? { bg: '#f0f0f0', color: '#666' }
  return (
    <span
      className="status-badge"
      style={{
        background: s.bg,
        color: s.color,
        padding: '2px 10px',
        borderRadius: 999,
        fontSize: '0.75rem',
        fontWeight: 600,
        textTransform: 'capitalize',
      }}
    >
      {status.replace('_', ' ')}
    </span>
  )
}

// ────────────────────────────────────────────────────────────────────────────
// Page — renders the product catalog with a sync trigger
// ────────────────────────────────────────────────────────────────────────────

export default async function CatalogPage() {
  const products = await getAllProducts()
  const lastSync = getLastSyncTimestamp()

  /**
   * Inline Server Action — the sync trigger.
   *
   * 1.  Calls the ERP/PIM sync to refresh pricing, inventory, and statuses.
   * 2.  Invalidates the cached catalog so the next page view triggers a
   *     background re-fetch while serving the stale (pre-sync) data
   *     immediately — stale-while-revalidate.
   *
   * Because the action calls revalidateTag **after** the data-layer sync, the
   * background re-fetch picks up the newly-updated products.  The admin never
   * blocks on the sync itself.
   */
  async function syncCatalog(formData) {
    'use server'

    // Update the underlying data (simulates an upstream ERP/PIM feed).
    await syncCatalogFromERP()

    // Mark the "products" cache tag as stale.  The next page visit will serve
    // stale cached data while fresh data is fetched in the background
    // (stale-while-revalidate), avoiding a blocking re-compute for every
    // operator who browses the catalog.
    revalidateTag('products', 'max')
  }

  return (
    <div className="catalog-page">

      {/* ── Page header ───────────────────────────────────── */}
      <div className="catalog-header">
        <div>
          <h1 className="catalog-title">Product Catalog</h1>
          <p className="catalog-subtitle">
            {products.length} products ·{' '}
            Last synced{' '}
            <time
