              title={formatTimestamp(lastSync)}
            >
              {timeAgo(lastSync)}
            </time>
          </p>
        </div>

        {/* ── Sync form ──────────────────────────────────────── */}
        <form action={syncCatalog}>
          <button type="submit" className="sync-btn">
            <svg
              width="16"
              height="16"
              viewBox="0 0 16 16"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
              style={{ marginRight: 6 }}
            >
              <path d="M1 8a7 7 0 0 1 13.2-3.3" />
              <path d="M15 1v4h-4" />
              <path d="M15 8a7 7 0 0 1-13.2 3.3" />
              <path d="M1 15v-4h4" />
            </svg>
            Sync Latest Catalog
          </button>
        </form>
      </div>

      {/* ── Product table ──────────────────────────────────── */}
      <div className="catalog-table-wrap">
        <table className="catalog-table">
          <thead>
            <tr>
              <th>SKU</th>
              <th>Name</th>
              <th className="num">Price</th>
              <th className="num">Inventory</th>
              <th>Status</th>
              <th>Last Updated</th>
            </tr>
          </thead>
          <tbody>
            {products.length === 0 ? (
              <tr>
                <td colSpan={6} className="empty">
                  No products found.
                </td>
              </tr>
