              products.map((p) => (
                <tr key={p.id}>
                  <td className="sku">{p.id}</td>
                  <td className="name">{p.name}</td>
                  <td className="num">
                    ${p.price.toLocaleString('en-US', { minimumFractionDigits: 0 })}
