          cursor: help;
        }

        /* ── Sync button ─────────────────────────────────── */
        .sync-btn {
          display: inline-flex;
          align-items: center;
          padding: 0.5rem 1rem;
          font-size: 0.875rem;
          font-weight: 600;
          color: #fff;
          background: var(--accent);
          border: none;
          border-radius: 6px;
          cursor: pointer;
          white-space: nowrap;
          transition: background 0.15s;
        }

        .sync-btn:hover {
          background: var(--accent-hover);
        }

        .sync-btn:active {
          transform: scale(0.98);
        }

        /* ── Table ───────────────────────────────────────── */
        .catalog-table-wrap {
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: 8px;
